import sailpoint.object.Identity;
import sailpoint.object.Filter;
Identity identity=null;
if(formModel!=null @and formModel.get("primaryAccount")!=null){
String identityId=formModel.get("primaryAccount");
Filter filter=Filter.or(Filter.eq("name",identityId),Filter.eq("id",identityId));
identity=context.getUniqueObject(Identity.class,filter);
workflow.put("identity",identity);
workflow.put("identityName",identity.getName());
if(wfcontext!=null @and wfcontext.getWorkflowCase()!=null @and  wfcontext.getWorkflowCase().getTaskResult()!=null){
wfcontext.getWorkflowCase().getTaskResult().setName(secondaryIdType+" -Account For "+identity.getName());
}
return identity;
}else{
throw new Exception("formModel primaryAccount value is null...");
}

